targetCode.css:
body {
  display: grid;
  place-items: center;
  min-height: 100vh;
  background: #f4f7f5;
  font-family: system-ui, sans-serif;
}

.card {
  width: 300px;
  padding: 24px;
  background: white;
  border-radius: 14px;
  box-shadow: 0 8px 18px rgba(15, 30, 25, 0.08);
  display: grid;
  gap: 10px;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}

.card h2 {
  margin: 0;
  color: #17201e;
}

.card p {
  margin: 0;
  color: #5b655f;
  line-height: 1.5;
}

.card a {
  color: #2a9d8f;
  font-weight: 700;
  text-decoration: none;
}

.card:hover {
  transform: translateY(-6px);
  box-shadow: 0 18px 32px rgba(15, 30, 25, 0.18);
}
